SELECT gen_random_uuid(), v.name, v.client_name, v.equipment,
       -- CAST to the enum: a text-typed CASE won't assign into the exercise_category column.
       (CASE v.region WHEN 'Systemic' THEN 'systemic' WHEN 'Powerlifting' THEN 'powerlifting' ELSE 'strength' END)::public.exercise_category,
