JOIN body_regions r ON r.display_name = v.region
JOIN muscles m ON m.display_name = v.muscle AND m.primary_region_id = r.id
LEFT JOIN muscle_subdivisions sd ON sd.muscle_id = m.id AND sd.display_name = v.subdivision
-- 39 of the 576 names already exist as retained (deactivated) strength rows, and name is
-- UNIQUE table-wide. All 39 are the SAME movement re-authored (equipment + muscle verified),
-- so upgrade them IN PLACE: keep the existing row id (programs referencing them auto-upgrade
-- to the canonical version), overwrite the canonical columns, and re-activate.
ON CONFLICT (name) DO UPDATE SET
  client_name         = EXCLUDED.client_name,
  equipment           = EXCLUDED.equipment,
  category            = EXCLUDED.category,
  muscle_group        = EXCLUDED.muscle_group,
  subdivision         = EXCLUDED.subdivision,
  movement_pattern    = EXCLUDED.movement_pattern,
  positioning         = EXCLUDED.positioning,
  grip                = EXCLUDED.grip,
  laterality          = EXCLUDED.laterality,
  resistance_profiles = EXCLUDED.resistance_profiles,
  muscle_id           = EXCLUDED.muscle_id,
  subdivision_id      = EXCLUDED.subdivision_id,
  is_global           = true,
  is_active           = true;


COMMIT;
